class FenwickTree:
    def __init__(self, size):
        self.n = size
        self.tree = [0] * (self.n + 1)  # 1-based indexing

    def update(self, idx, delta):
        idx += 1  # Convert to 1-based index
        while idx <= self.n:
            self.tree[idx] += delta
            idx += idx & -idx

    def query(self, idx):
        res = 0
        idx += 1  # Convert to 1-based index
        while idx > 0:
            res += self.tree[idx]
            idx -= idx & -idx
        return res

class Solution:
    def popcountDepth(self, nums: List[int], queries: List[List[int]]) -> List[int]:
        n = len(nums)
        if n == 0:
            return []

        depths = [0] * n
        for i in range(n):
            x = nums[i]
            d = 0
            while x != 1:
                x = bin(x).count('1')
                d += 1
            depths[i] = d

        max_depth = max(depths) if n > 0 else 0
        trees = [FenwickTree(n) for _ in range(6)]  # Depths 0 to 5

        for i in range(n):
            d = depths[i]
            if d <= 5:
                trees[d].update(i, 1)

        res = []
        for query in queries:
            if query[0] == 1:
                l, r, k = query[1], query[2], query[3]
                if k > 5:
                    res.append(0)
                    continue
                cnt = trees[k].query(r) - trees[k].query(l - 1)
                res.append(cnt)
            else:
                idx, val = query[1], query[2]
                old_d = depths[idx]
                x = val
                d = 0
                while x != 1:
                    x = bin(x).count('1')
                    d += 1
                new_d = d
                depths[idx] = new_d
                if old_d <= 5:
                    trees[old_d].update(idx, -1)
                if new_d <= 5:
                    trees[new_d].update(idx, 1)
        return res

